import 'jspdf-autotable';
import jsPDF from 'jspdf';
import moment from 'moment';
import * as XLSX from 'xlsx';
import DatePicker from 'react-datepicker';
import { useSelector } from 'react-redux';
import DataTable from 'react-data-table-component';
import { Link, useNavigate } from 'react-router-dom';
import React, { Fragment, useState, useEffect, useRef } from 'react';
import { Card, CardHeader, CardBody, Dropdown, DropdownToggle, DropdownMenu, DropdownItem, Form, Row, Col } from 'reactstrap';


import OverDues from '../Enquiries/OverDues';
import Widgets from '../../Common/Progress/Widgets';
import { leadsColumns } from '../ColumnHeader/Header';
import { conditionalRow } from '../../Common/Rowstyle/Rowstyle';
import { H3, Btn, Breadcrumbs } from '../../../AbstractElements';
import { getClientUrlDataToken, } from '../../../Utils/restUtils';
import { Search, Filter, Export, leadsList } from '../../../Constant';
import Transparentspinner from '../../Common/Loader/Transparentspinner';
import { getArea, getAreaRole, showLead, leadsCounts, leadsCountsRole, getUsers, getUsersRole, showLeadRole } from '../../../CommonUrl';


const LeadsList = () => {
  const searchParams = location.search;
  const params = new URLSearchParams(searchParams);


  const [spinnerTrans, setspinnerTrans] = useState(false);
  const [customerLists, setCustomerList] = useState([]);
  const [resetPaginationToggle, setResetPaginationToggle] = useState(false);
  const [totalRows, setTotalRows] = useState(0);
  const [perPage, setPerPage] = useState(10);
  const [currentPage, setCurrentPage] = useState(1);

  const [userData, setUserData] = useState([]);
  const [staticwidgets, setstaticwidgets] = useState([])
  const [filters, setFilters] = useState({
    search: params.get('search') || '',
    start_date: params.get('start_date') ? moment(params.get('start_date'), "DD-MM-YYYY").toDate() : '',
    end_date: params.get('end_date') ? moment(params.get('end_date'), "DD-MM-YYYY").toDate() : '',
    userId: params.get("user") || '',
    stage: params.get("stage") || '',
  });
  const [dateRange, setDateRange] = useState([filters.start_date, filters.end_date]);
  const [startDate, endDate] = dateRange
  const [sortConfig, setSortConfig] = useState({ column: '', order: '' });
  const [dropdownOpen, setDropdownOpen] = useState(false);

  const formatStartDate = filters.start_date ? moment(filters.start_date).format("DD-MM-YYYY") : '';
  const formatEndDate = filters.end_date ? moment(filters.end_date).format("DD-MM-YYYY") : '';

  const navigate = useNavigate();
  const authState = useSelector((state) => state.auth);

  const toggleDropdown = () => setDropdownOpen(!dropdownOpen);
  const toggleStyle = { padding: '10px 20px', opacity: '0.8', fontSize: '14px' }


  const enquiryStatusOptions = [
    { label: 'Prospect', value: 'prospect' },
    { label: 'Negotiation', value: 'negotiation' },
    { label: 'Won', value: 'won' },
    { label: 'Lost', value: 'lost' },
  ];

  useEffect(() => {
    fetchEnquiry(1);
    getwidgetsdata();
    getuserData()
  }, []);




  const handleApiError = (status) => {
    if (status >= 400 && status <= 405) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
    } else if (status >= 500 && status <= 505) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
    } else {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
    }
  };

  const handleSort = (column) => {
    let newOrder = 'asc';
    if (sortConfig.column === column.id) {
      newOrder = sortConfig.order === 'asc' ? 'desc' : 'asc';
    }
    setSortConfig({ column: column.id, order: newOrder });
    fetchEnquiry(currentPage, perPage, filters.searchKey, filters.start_date, filters.end_date, filters.areaFilter, filters.cust_status_Filter, column.id, newOrder);
  };

  const getuserData = async () => {
    const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getUsers : getUsersRole);
    if (data.status === true) {
      setUserData(data.data);
    } else {
      handleApiError(data.status);
    }
  };





  const getwidgetsdata = async () => {
    const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? leadsCounts : leadsCountsRole);
    if (data.status === true) {
      setstaticwidgets(data.data);
    } else {
      handleApiError(data.status);
    }
  }


  const fetchEnquiry = async (page, size = perPage, start_date = '', end_date = '', areaFilter = '', cust_status_Filter = '', sortBy = '', sortOrder = '') => {
    setspinnerTrans(true)
    const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? showLead +
      `?page=${page}&page_length=${size}&search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&stage=${filters.stage}&sort_by=${sortBy}&sort_order=${sortOrder}&user_id=${filters.userId}` :
      showLeadRole + `?page=${page}&page_length=${size}&search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&stage=${filters.stage}&sort_by=${sortBy}&sort_order=${sortOrder}&user_id=${filters.userId}`);
    if (response.status === true) {
      setResetPaginationToggle(!resetPaginationToggle);
      const SerialNo = (page - 1) * size + 1;
      setCustomerList(response.data.data.map((e, index) => {
        return {
          Si: SerialNo + index,
          name: e.name || 'N/A',
          Mobile: e?.country_code ? "+" + e?.country_code + " " + e?.phone : e?.phone,
          product: e?.product_name || 'N/A',
          Status: e.stage || 'N/A',
          created: e?.next_followup_date || 'N/A',
          assigned: e?.assigned_user_name || 'N/A',
          leadId: e?.lead_id || 'N/A',
          expectedValue: e?.expected_value || 'N/A',
          id: e?.id

        }
      }))
      setTotalRows(response.data.total);
    } else {
      handleApiError(response.status);
    }
    setspinnerTrans(false)
  };

  const exportCustomerExcel = async () => {
    setspinnerTrans(true)
    const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ?
      showLead + `?export=lead_data&search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&stage=${filters.stage}&user_id=${filters.userId}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`
      : showLeadRole + `?export=lead_data&search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&stage=${filters.stage}&user_id=${filters.userId}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`);
    const dataToExport = response.data.map(({ lead_id, name, phone, stage, assigned_user_name, next_followup_date }) => ({
      Lead_Id: lead_id,
      Name: name,
      Phone: phone,
      Stage: stage,
      Assigned_User_Name: assigned_user_name,
      Next_Followup_Date: next_followup_date
    }));
    if (response.status === true) {
      const ws = XLSX.utils.json_to_sheet(dataToExport);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, 'Lead Data');
      XLSX.writeFile(wb, 'lead_data.xlsx');
    } else {
      handleApiError(response.status);
    }
    setspinnerTrans(false)
  };

  const exportCustomerPdf = async () => {
    setspinnerTrans(true)
    const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ?
      showLead + `?export=customer_data&search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&stage=${filters.stage}&user_id=${filters.userId}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`
      : showLeadRole + `?export=customer_data&search=${filters.search}&start_date=${formatStartDate}&end_date=${formatEndDate}&stage=${filters.stage}&user_id=${filters.userId}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}&sort_by=${sortConfig.column}&sort_order=${sortConfig.order}`);
    const dataToExport = response.data.map(({ lead_id, name, phone, stage, status, assigned_user_name, next_followup_date }, index) => ({ Sl: index + 1, lead_id, name, phone, stage, status, assigned_user_name, next_followup_date }));
    if (response.status === true) {
      const doc = new jsPDF();
      const heading = "Customer's list";
      doc.setFontSize(18);
      doc.setFont("helvetica", "bold");
      doc.text(heading, 14, 22);
      const columns = ["Sl", "Lead Id", "Name", "Mobile", "Stage", "Expected Value", "Assign", "Next-Follow-up",];
      const rows = dataToExport.map(({ lead_id, name, phone, stage, status, assigned_user_name, next_followup_date }, index) => [index + 1, lead_id, name, phone, stage, status, assigned_user_name, next_followup_date]);
      doc.autoTable({
        head: [columns],
        body: rows,
        margin: { top: 6, left: 6, right: 6, bottom: 6 }, // remove all margins

        styles: { fontSize: 10 },
        headStyles: { fillColor: [100, 150, 200] },
      });
      doc.save("lead_list.pdf");
    } else {
      handleApiError(response.status);
    }
    setspinnerTrans(false)
  };


  const handlePageChange = page => {
    fetchEnquiry(page, perPage, filters.searchKey, filters.start_date, filters.end_date, filters.areaFilter, filters.cust_status_Filter, sortConfig.column, sortConfig.order);
    setCurrentPage(page);
  };

  const handlePerRowsChange = async (newPerPage, page) => {
    fetchEnquiry(page, newPerPage, filters.searchKey, filters.start_date, filters.end_date, filters.areaFilter, filters.cust_status_Filter, sortConfig.column, sortConfig.order);
    setPerPage(newPerPage);
  };

  const handleFilter = async (e) => {
    e.preventDefault();


    const start_date = startDate ? moment(startDate).format("DD-MM-YYYY") : '';
    const end_date = endDate ? moment(endDate).format("DD-MM-YYYY") : '';



    const queryParams = new URLSearchParams({
      search: filters.search,
      start_date,
      end_date,
      user: filters?.userId,
      stage: filters?.stage,
      sortBy: sortConfig.column || '',
      sortOrder: sortConfig.order || '',
    }).toString();
    navigate(`/lead-manage/leads?${queryParams}`);

    fetchEnquiry(currentPage, perPage, start_date, end_date, sortConfig.column, sortConfig.order);
  };



  return (
    <>
      {spinnerTrans && <Transparentspinner />}
      <Breadcrumbs mainTitle={leadsList} parent="Lead Manager" title={leadsList} />
      <Widgets details={staticwidgets} />

      <OverDues authState={authState} />
      <Card className='cardWidth mt-4'>
        <CardHeader style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <H3>{leadsList}</H3>
          <Dropdown className='m-0' isOpen={dropdownOpen} toggle={toggleDropdown}>
            <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4">
              {Export} <i className="icofont icofont-arrow-up"></i>
            </DropdownToggle>
            <DropdownMenu container="body">
              <DropdownItem style={toggleStyle} onClick={() => exportCustomerExcel()}><i className="fa fa-file-excel-o me-2"></i> Excel</DropdownItem>
              <DropdownItem style={toggleStyle} onClick={() => exportCustomerPdf()}><i className="fa fa-file-pdf-o me-2"></i> Pdf</DropdownItem>
            </DropdownMenu>
          </Dropdown>


        </CardHeader>
        <CardBody>
          <span className=''>
            <Form className="needs-validation" noValidate onSubmit={handleFilter}>
              <Row className="ps-3 gap-sm-3 gap-md-2 mb-4 filterGap">
                <Col sm="12" md='5' lg='2'>
                  <input className="form-control"
                    onChange={(e) => { setFilters({ ...filters, search: e.target.value }) }}
                    placeholder={Search}
                    type="text"
                    value={filters.search}
                  />
                </Col>


                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <DatePicker
                      className="form-control digits w-100"
                      selectsRange
                      startDate={startDate}
                      endDate={endDate}
                      onChange={(update) => {
                        setDateRange(update);
                      }}
                      isClearable={startDate ? true : false}
                      monthsShown={2}
                      dateFormat="dd/MM/yyyy"
                      popperPlacement="bottom"
                      calendarClassName='parallel-calendar'
                      placeholderText='Select Date Range'
                    />
                  </div>
                </Col>
                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <select value={filters.userId || ''} onChange={(e) => { setFilters({ ...filters, userId: e.target.value }) }} className='form-control ' name="" id="">
                      <option value=''>Assigned User</option>
                      {
                        userData?.map((item) => (
                          <option key={item?.user_id} value={item?.user_id}>{item?.user_name}</option>
                        ))
                      }
                    </select>

                  </div>
                </Col>
                <Col sm="12" md="5" lg='2' className="form-element" >
                  <div style={{ position: 'relative', zIndex: 2 }}>
                    <select value={filters.stage} onChange={(e) => { setFilters({ ...filters, stage: e.target.value }) }} className='form-control ' name="" id="">
                      <option value={''}> Stage</option>
                      {
                        enquiryStatusOptions?.map((item) => (
                          <option key={item?.value} value={item?.value}>{item?.label}</option>
                        ))
                      }
                    </select>

                  </div>
                </Col>
                <Col sm="12" md="5" lg='1' className="custom-filtrs">
                  <Btn attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                </Col>
              </Row>
            </Form>
          </span>

          <div className="order-history table-responsive">
            <DataTable
              columns={leadsColumns(authState)}
              data={customerLists}
              // progressPending={loading}
              pagination
              paginationServer
              defaultSortAsc
              onSort={handleSort}
              sortServer
              paginationRowsPerPageOptions={[10, 25, 50, 100]}
              paginationTotalRows={totalRows}
              paginationDefaultPage={currentPage}
              onChangeRowsPerPage={handlePerRowsChange}
              conditionalRowStyles={conditionalRow}
              onChangePage={handlePageChange}
              fixedHeader
            />
          </div>
        </CardBody>
      </Card>


    </>
  )
}

export default LeadsList